import { List } from 'immutable'
import { PSPDFKitError, invariant } from '@pspdfkit/shared'
import { getBrowserSpawner } from '@pspdfkit/core'

import { getElectronAppId } from '@/utils/products'
import { getBaseUrl, getCoreMainThreadOrigin } from '@/utils/environment'
import StandaloneBackend from './StandaloneBackend'
import { base64EncodeCertificate } from '@/utils/digitalSignatures'
import { SignatureFeatureAvailability } from '@/enums/SignatureFeatureAvailability'
import { hasWebAnnotationEditingFeature } from '@/utils/permissions'
import { ProductId } from '@/enums/ProductId'
import { getDocumentBuffer } from '@/utils/document'
import { getGdPicturePromise, initializeGdPictureClient, setGdPicturePromise } from '@/load'
import { retrieveCustomFonts } from '@/utils/fontFaces'

import type { IProductId } from '@/enums/ProductId'
import type { normalizeCoreOptions } from './StandaloneBackend'
import type { LoadOptions, LoadResponse } from '@/typings/backend'
import type { StandaloneConfiguration } from '@/Configuration'
import type { FetchedCustomFont } from '@pspdfkit/core'
import type { IClient } from '@/typings/models'
import type { FontSubstitution } from '@/models/FontSubstitution'

let previousLicenseKey

export {
  corePool,
  validateStandaloneConfiguration,
  normalizeCoreOptions,
} from './StandaloneBackend'

const progressIncrement = 0.3

export default class StandaloneBackendWASM extends StandaloneBackend {
  destroyed: boolean

  constructor(configuration: StandaloneConfiguration) {
    const baseUrl = configuration.baseUrl || getBaseUrl(window.document)
    const baseCoreUrl = configuration.baseCoreUrl || baseUrl
    const baseProcessorEngineUrl = configuration.baseProcessorEngineUrl || baseUrl
    const configWithBaseUrl = { ...configuration, baseUrl, baseCoreUrl, baseProcessorEngineUrl }

    if (typeof configWithBaseUrl.baseUrl !== 'string') {
      throw new PSPDFKitError(
        '`baseUrl` is mandatory and must be a valid URL, e.g. `https://example.com/`',
      )
    }

    // Validate document
    if (
      typeof configWithBaseUrl.document !== 'string' &&
      !(configWithBaseUrl.document instanceof ArrayBuffer)
    ) {
      throw new PSPDFKitError(
        'document must be either an URL to a supported document type (PDF and images), e.g. `https://example.com/document.pdf`, or an `ArrayBuffer`',
      )
    }

    // Validate licenseKey
    if (previousLicenseKey && previousLicenseKey !== configWithBaseUrl.licenseKey) {
      throw new PSPDFKitError(
        `Trying to re-use instance with a different licenseKey.
Unfortunately we only allow one licenseKey per instance.
Please contact support for further assistance.`,
      )
    } else if (
      typeof configWithBaseUrl.licenseKey === 'string' &&
      configWithBaseUrl.licenseKey.startsWith('TRIAL-')
    ) {
      throw new PSPDFKitError(`You're using the npm key instead of the license key. This key is used to download the PSPDFKit for Web package via the node package manager.

Leave out the license key to activate as a trial.`)
    }

    super(configWithBaseUrl)
    this.destroyed = false
  }

  override async load(options: LoadOptions = {}): Promise<LoadResponse> {
    let progressToReport = 0.2

    options.progressCallback && options.progressCallback('loading', progressToReport)

    this._isPDFJavaScriptEnabled = options.isPDFJavaScriptEnabled

    const documentBufferPromise = getDocumentBuffer(
      this._state.baseUrl,
      this._state.document,
      this._state.productId as IProductId,
      () => {
        progressToReport += progressIncrement
        options.progressCallback && options.progressCallback('loading', progressToReport)
      },
    )

    const res = await loadModule(this.client, this._state).finally(() => {
      progressToReport += progressIncrement
      options.progressCallback && options.progressCallback('loading', progressToReport)
    })

    invariant(res)

    const { features, signatureFeatureAvailability } = res

    if (
      this._state.productId === ProductId.SharePoint &&
      typeof this._state.document === 'string' &&
      Array.isArray(res.afu)
    ) {
      const documentUrl = new URL(this._state.document, this._state.baseUrl)

      if (!res.afu.some(regEntry => documentUrl.hostname.match(regEntry))) {
        throw new PSPDFKitError(`The document origin ${documentUrl.hostname} is not authorized.`)
      }
    }

    const finalSignatureFeatureAvailability =
      signatureFeatureAvailability === SignatureFeatureAvailability.ELECTRONIC_SIGNATURES &&
      hasWebAnnotationEditingFeature(features) &&
      this._state.forceLegacySignaturesFeature
        ? SignatureFeatureAvailability.LEGACY_SIGNATURES
        : signatureFeatureAvailability

    this._state = this._state
      .set('features', List(features))
      .set('signatureFeatureAvailability', finalSignatureFeatureAvailability)

    previousLicenseKey = this._state.licenseKey

    const documentBuffer = await documentBufferPromise
    let documentResponse
    let documentBufferCopy: ArrayBuffer | null

    documentBufferCopy = documentBuffer.slice(0)

    try {
      if (this.destroyed) {
        documentBufferCopy = null
        // Unloading an instance that didn't finish loading and then loading
        // a new one could lead to an edge race condition if the current
        // StandaloneBackendWASM instance gets destroyed while the previous load() call
        // didn't get to open the document yet. Since the underlying CoreClient instance
        // is recycled between instances of StandaloneBackendWASM, the call to
        // this.client.openDocument() would set the _hasOpenedDocument flag to true,
        // and the new StandaloneBackendWASM instance attempt to load the same
        // CoreClient instance would fail because of the initial invariant check to
        // prevent calling load() on the same CoreClient twice.
        // So, at this point if a call to destroy() on this instance was made,
        // we can await to a promise that will never fulfill and avoid the rest
        // of this method being added to the task queue.
        documentResponse = await new Promise(() => {})
      } else {
        documentResponse = await this.client.openDocument(
          documentBuffer,
          options.password,
          typeof options.initialPageIndex === 'number' ? options.initialPageIndex : 0,
        )
        documentBufferCopy = null
      }
    } catch (error) {
      // When we get an INVALID_PASSWORD error, the PDF is transferred back to the main thread
      // and we need to save it again in the state.
      if (error.message === 'INVALID_PASSWORD' && this._state.document instanceof ArrayBuffer) {
        this._state = this._state.set('document', error.callArgs[0])
      }

      if (error.message === 'IMAGE_DOCUMENTS_NOT_LICENSED') {
        error.message =
          'The image documents feature is not enabled for your license key. Please contact support or sales to purchase the UI module for your product.'
      }

      if (
        error instanceof PSPDFKitError &&
        error.message.includes('File not in PDF format or corrupted.') &&
        this._state.productId !== ProductId.Salesforce
      ) {
        invariant(documentBufferCopy)

        let GdPicturePromise = getGdPicturePromise()
        let GdPictureClient

        try {
          if (!GdPicturePromise) {
            GdPicturePromise = initializeGdPictureClient({
              baseUrl: this._state.baseProcessorEngineUrl,
              mainThreadOrigin: this._state.appName || getElectronAppId() || window.location.origin,
              licenseKey: this._state.licenseKey || undefined,
              customFonts: this._state.customFonts || undefined,
              dynamicFonts: this._state.dynamicFonts || undefined,
              fontSubstitutions: this._state.fontSubstitutions as FontSubstitution[] | undefined,
              processorEngine: this._state.processorEngine as string | undefined,
            })

            setGdPicturePromise(GdPicturePromise)
          }

          GdPictureClient = await GdPicturePromise

          invariant(GdPictureClient)

          const convertedDocument = await GdPictureClient.toPdf(documentBufferCopy)

          documentResponse = await this.client.openDocument(
            convertedDocument,
            options.password,
            typeof options.initialPageIndex === 'number' ? options.initialPageIndex : 0,
          )
        } catch (innerError) {
          if (
            innerError.message === 'INVALID_PASSWORD' &&
            this._state.document instanceof ArrayBuffer
          ) {
            this._state = this._state.set('document', error.callArgs[0])
          }

          if (innerError.message === 'IMAGE_DOCUMENTS_NOT_LICENSED') {
            innerError.message =
              'The image documents feature is not enabled for your license key. Please contact support or sales to purchase the UI module for your product.'
          }

          throw innerError
        } finally {
          documentBufferCopy = null
          GdPictureClient?.destroy()

          setGdPicturePromise(null)
        }
      } else {
        throw error
      }
    }

    if (this._isPDFJavaScriptEnabled) {
      this._initialChanges = await this.client.enablePDFJavaScriptSupport()
    }

    if (this._XFDF) {
      await this.client.importXFDF(
        this._XFDF.source,
        this._XFDF.keepCurrentAnnotations,
        this._XFDF.ignorePageRotation,
      )
    }

    // If the backend was instantiated with an instant JSON, we need to verify that the
    // pdfId if present
    if (this._instantJSON && this._instantJSON.pdfId && documentResponse.ID.permanent) {
      const expectedIds = this._instantJSON.pdfId
      const actualIds = documentResponse.ID

      if (expectedIds.permanent !== actualIds.permanent) {
        throw new PSPDFKitError(`Could not instantiate from Instant JSON: Permanent PDF ID mismatch.
Please use the same PDF document that was used to create this Instant JSON.
For more information, please visit: https://pspdfkit.com/guides/web/current/importing-exporting/instant-json/`)
      }

      if (expectedIds.changing !== actualIds.changing) {
        throw new PSPDFKitError(`Could not instantiate from Instant JSON: Changing PDF ID mismatch.
Please use the same revision of this PDF document that was used to create this Instant JSON.
For more information, please visit: https://pspdfkit.com/guides/web/current/importing-exporting/instant-json/`)
      }
    }

    if (this._trustedCAsCallback) {
      try {
        const certificates = await this._trustedCAsCallback()

        if (!Array.isArray(certificates)) {
          throw new PSPDFKitError('Certificates response must be an array')
        }

        if (certificates.some(cert => !(cert instanceof ArrayBuffer) && typeof cert !== 'string')) {
          throw new PSPDFKitError(
            'All certificates must be passed as ArrayBuffer (DER) or string (PEM)',
          )
        }

        await this.client.loadCertificates(certificates.map(base64EncodeCertificate))
      } catch (e) {
        throw new PSPDFKitError(
          `Could not retrieve certificates for digital signatures validation: ${e.message}.`,
        )
      }
    }

    // We should then set them in the StandaloneBackendState and return them in this method as a list.
    this._state = this._state.set('documentResponse', documentResponse)

    return {
      features: this._state.features,
      signatureFeatureAvailability: this._state.signatureFeatureAvailability,
      hasPassword: !!options.password,
      allowedTileScales: 'all',
      evaluation: res.evaluation,
    }
  }

  override destroy(): void {
    this.destroyed = true
    super.destroy()
  }

  getCustomFontsPromise(): { current: Promise<FetchedCustomFont[]> | null | undefined } {
    return customFontsPromiseRef
  }
}

// Exported to reset on tests
export const customFontsPromiseRef: {
  current: Promise<Array<FetchedCustomFont>> | null | undefined
} = {
  current: undefined,
}

export async function loadModule(client: IClient, config: ReturnType<typeof normalizeCoreOptions>) {
  customFontsPromiseRef.current =
    customFontsPromiseRef.current ||
    (config.customFonts
      ? (retrieveCustomFonts(config.customFonts) as Promise<Array<FetchedCustomFont>>)
      : undefined)

  const mainThreadOrigin = getCoreMainThreadOrigin(config.appName)
  const workerSpawnerFn = () => getBrowserSpawner(config.inlineWorkers)

  return client
    .loadNativeModule(config.baseCoreUrl, {
      mainThreadOrigin,
      disableWebAssemblyStreaming: config.disableWebAssemblyStreaming,
      enableAutomaticLinkExtraction: config.enableAutomaticLinkExtraction,
      overrideMemoryLimit: config.overrideMemoryLimit,
      workerSpawnerFn,
    })
    .then(async () =>
      client.load(config.baseCoreUrl, config.licenseKey, {
        mainThreadOrigin,
        ...(customFontsPromiseRef.current
          ? { customFonts: await customFontsPromiseRef.current }
          : null),
        dynamicFonts: config.dynamicFonts,
        productId: config.productId,
      }),
    )
}
